export function fakeLspServerSource(): string {
	return [
		'const HEADER_SEPARATOR = "\\r\\n\\r\\n";',
		"let inputBuffer = Buffer.alloc(0);",
		"process.stdin.on('data', (chunk) => {",
		"	inputBuffer = Buffer.concat([inputBuffer, Buffer.from(chunk)]);",
		"	drain();",
		"});",
		"function drain() {",
		"	while (true) {",
		"		const headerEnd = inputBuffer.indexOf(HEADER_SEPARATOR);",
		"		if (headerEnd === -1) return;",
		"		const headers = inputBuffer.subarray(0, headerEnd).toString('ascii');",
		"		const match = /Content-Length: (\\d+)/i.exec(headers);",
		"		if (!match) throw new Error('missing content length');",
		"		const bodyStart = headerEnd + Buffer.byteLength(HEADER_SEPARATOR);",
		"		const bodyEnd = bodyStart + Number(match[1]);",
		"		if (inputBuffer.length < bodyEnd) return;",
		"		const body = inputBuffer.subarray(bodyStart, bodyEnd).toString('utf8');",
		"		inputBuffer = inputBuffer.subarray(bodyEnd);",
		"		handle(JSON.parse(body));",
		"	}",
		"}",
		"function send(message) {",
		"	const body = JSON.stringify(message);",
		"	process.stdout.write('Content-Length: ' + Buffer.byteLength(body, 'utf8') + HEADER_SEPARATOR + body);",
		"}",
		"function handle(message) {",
		"	if (message.method === 'exit') process.exit(0);",
		"	if (!Object.hasOwn(message, 'id')) return;",
		"	if (message.method === 'initialize') {",
		"		send({ jsonrpc: '2.0', id: message.id, result: { capabilities: {} } });",
		"		return;",
		"	}",
		"	if (message.method === 'textDocument/diagnostic') {",
		"		send({ jsonrpc: '2.0', id: message.id, result: { items: [] } });",
		"		return;",
		"	}",
		"	if (message.method === 'shutdown') {",
		"		send({ jsonrpc: '2.0', id: message.id, result: null });",
		"		return;",
		"	}",
		"	send({ jsonrpc: '2.0', id: message.id, error: { code: -32601, message: 'method not found' } });",
		"}",
		"process.stdin.resume();",
	].join("\n");
}
